// Стан додатку
let currentUser = null;
let cart = [];
let users = JSON.parse(localStorage.getItem('users')) || [];
let currentPage = 'store';
let sliderInterval;

// DOM елементи
const overlay = document.getElementById('overlay');
const mainContent = document.getElementById('mainContent');
